export function getVariants(name: string): NameVariant[] {
  const raw = NAME_VARIANTS[name.toLowerCase()]
  if (!raw) return []
  return raw.map((s) => {
    const i = s.indexOf('|')
    return i < 0 ? { name: s } : { name: s.slice(0, i), lang: s.slice(i + 1) }
  })
}
